INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-57f41407-moex-00142', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於偵查不公開原則，下列敘述何者錯誤？', '["偵查不公開原則之目的，一方面是確保無罪推定原則，一方面則避免犯罪嫌疑人逃匿或證據被湮滅", "偵查不公開原則仍有例外，於依法令或維護公共利益、保護合法權益而有必要時，仍得公開或揭露 偵查中因執行職務知悉之事項予執行法定職務必要範圍以外之人員", "犯罪嫌疑人之辯護人並非公務員，因此關於其於偵查中依法執行職務所知悉之事項，得公開或揭露 之，不受法律之限制", "犯罪嫌疑人之辯護人得於檢察官訊問犯罪嫌疑人時在場，並得陳述意見，自亦有權得就所得悉之事 項筆記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00143', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於「告訴」或「告發」之敘述，下列何者錯誤？', '["告訴乃論之罪，對於共犯之一人告訴者，其效力及於其他共犯", "告訴乃論之罪，對於共犯之一人撤回告訴者，其效力及於其他共犯", "不問何人知有犯罪嫌疑者，得為告發", "公務員因執行職務知有犯罪嫌疑者，得為告發"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00144', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於起訴或不起訴之敘述，下列何者錯誤？', '["檢察官偵查所得證據，認為被告雖有犯罪嫌疑，但如符合微罪不舉，或被告已受重罪之確定判決等 情形，仍得裁量不起訴", "檢察官偵查結果，認為被告有犯罪嫌疑，但被告之所在不明時，因未能聽取被告對於偵查所得證據 之意見，依法不能逕行提起公訴", "檢察官偵查結果，認為被告有犯罪嫌疑，但被告已死亡者，應不起訴處分", "再議制度是針對檢察官之監督制衡方法之一，告訴人原則上對於不起訴處分或緩起訴處分得再議， 被告對於撤銷緩起訴處分亦得再議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00145', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '檢察官如欲作成緩起訴處分，其要件不包括下列何者？', '["被告所犯為死刑、無期徒刑或最輕本刑3年以上有期徒刑以外之罪", "審酌刑法第57條之所列事由", "須考慮公共利益之維護", "須得法院之同意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00146', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '下列何種程序，非經被告到庭，不得進行？', '["第二審準備程序", "第二審審判程序", "第一審宣示判決", "第一審審判程序"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00147', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於審判程序之敘述，下列何者正確？', '["第一審法院於案件符合刑事訴訟法第449條規定之要件時，得為簡易判決處刑", "地方法院得就內亂罪之案件進行第一審法院之審理", "高等法院就內亂罪之案件，如被告先就被訴事實為有罪之陳述時，審判長得告知被告簡式審判程序 之旨，並聽取當事人、代理人、辯護人及輔佐人之意見後，裁定進行簡式審判程序", "第三審為事實審，得進行再審之開始審理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00148', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於刑事訴訟審判之簡易程序，第一審應如何審理？', '["法官一人獨任制", "法官二人合議制", "法官三人合議制", "法官五人合議制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00149', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '有關勘驗之規定，不得為下列何種處分？', '["檢查身體", "檢驗屍體", "解剖屍體", "採取尿液"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00150', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '依刑事訴訟法，下列何人得提起非常上訴？', '["檢察長", "檢察總長", "被告", "檢察官"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:14+00:00", "source_pdf_sha1": "0f8f6099d55e", "answer_pdf_sha1": "a6db6dc8e7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00151', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-114-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '下列有關法律「實效性」之敘述，何者錯誤？', '["係對於法律是否發揮規範功能的判斷", "指法律要求人民遵守的誡命", "指法律事實上為人民遵循之程度", "通常為法律社會學之研究對象"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d2e657417524", "answer_pdf_sha1": "22e4c65c048c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "703", "s": "0613", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
